  "inlineSchema": "// This is your Prisma schema file,\n// learn more about it in the docs: https://pris.ly/d/prisma-schema\n\n// Get a free hosted Postgres database in seconds: `npx create-db`\n\ngenerator client {\n  provider = \"prisma-client\"\n  //output   = \"../app/generated/prisma\"\n  output   = \"../src/lib/generated/prisma\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n}\n\n// ============================================\n// MODELOS BASE - MULTI-TENANT\n// ============================================\n\n// Tenant (Organización/Empresa)\nmodel Tenant {\n  id        String   @id @default(cuid())\n  name      String\n  slug      String   @unique // Subdominio: empresa.nextlms.com\n  logo      String?\n  plan      Plan     @default(FREE)\n  isActive  Boolean  @default(true)\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  // Relaciones\n  users   User[]\n  courses Course[]\n\n  @@map(\"tenants\")\n}\n\n// Planes de suscripción\nenum Plan {\n  FREE\n  STARTER\n  PRO\n  ENTERPRISE\n}\n\n// Usuario\nmodel User {\n  id            String    @id @default(cuid())\n  name          String?\n  email         String?\n  emailVerified DateTime? @map(\"email_verified\")\n  image         String?\n  password      String? // Null si usa OAuth\n  role          Role      @default(STUDENT)\n  isActive      Boolean   @default(true)\n  createdAt     DateTime  @default(now())\n  updatedAt     DateTime  @updatedAt\n\n  // Multi-tenant\n  tenantId String?\n  tenant   Tenant? @relation(fields: [tenantId], references: [id], onDelete: Cascade)\n\n  // Relaciones de autenticación\n  accounts Account[]\n  sessions Session[]\n\n  // Relaciones de LMS\n  enrollments  Enrollment[]\n  coursesOwned Course[]     @relation(\"CourseOwner\")\n\n  @@map(\"users\")\n}\n\n// Roles de usuario\nenum Role {\n  SUPER_ADMIN // Admin de la plataforma\n  ADMIN // Admin del tenant\n  INSTRUCTOR // Creador de cursos\n  STUDENT // Estudiante\n}\n\n// ============================================\n// MODELOS DE AUTENTICACIÓN (NextAuth)\n// ============================================\n\nmodel Account {\n  id                String  @id @default(cuid())\n  userId            String  @map(\"user_id\")\n  type              String\n  provider          String\n  providerAccountId String  @map(\"provider_account_id\")\n  refresh_token     String? @db.Text\n  access_token      String? @db.Text\n  expires_at        Int?\n  token_type        String?\n  scope             String?\n  id_token          String? @db.Text\n  session_state     String?\n  user              User    @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@unique([provider, providerAccountId])\n  @@map(\"accounts\")\n}\n\nmodel Session {\n  id           String   @id @default(cuid())\n  sessionToken String   @unique @map(\"session_token\")\n  userId       String   @map(\"user_id\")\n  expires      DateTime\n  user         User     @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@map(\"sessions\")\n}\n\nmodel VerificationToken {\n  identifier String\n  token      String   @unique\n  expires    DateTime\n\n  @@unique([identifier, token])\n  @@map(\"verification_tokens\")\n}\n\n// ============================================\n// MODELOS DEL LMS\n// ============================================\n\n// Curso\nmodel Course {\n  id          String   @id @default(cuid())\n  title       String\n  slug        String\n  description String?  @db.Text\n  thumbnail   String?\n  price       Decimal? @db.Decimal(10, 2)\n  isPublished Boolean  @default(false)\n  isFree      Boolean  @default(false)\n  createdAt   DateTime @default(now())\n  updatedAt   DateTime @updatedAt\n\n  // Multi-tenant\n  tenantId String\n  tenant   Tenant @relation(fields: [tenantId], references: [id], onDelete: Cascade)\n\n  // Propietario/Instructor\n  ownerId String\n  owner   User   @relation(\"CourseOwner\", fields: [ownerId], references: [id])\n\n  // Relaciones\n  modules     Module[]\n  enrollments Enrollment[]\n  categories  CategoriesOnCourses[]\n\n  @@unique([tenantId, slug])\n  @@map(\"courses\")\n}\n\n// Módulo de un curso\nmodel Module {\n  id        String   @id @default(cuid())\n  title     String\n  position  Int\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  courseId String\n  course   Course @relation(fields: [courseId], references: [id], onDelete: Cascade)\n\n  lessons Lesson[]\n\n  @@map(\"modules\")\n}\n\n// Lección de un módulo\nmodel Lesson {\n  id          String     @id @default(cuid())\n  title       String\n  content     String?    @db.Text\n  videoUrl    String?\n  position    Int\n  type        LessonType @default(TEXT)\n  isFree      Boolean    @default(false)\n  isPublished Boolean    @default(false)\n  createdAt   DateTime   @default(now())\n  updatedAt   DateTime   @updatedAt\n\n  moduleId String\n  module   Module @relation(fields: [moduleId], references: [id], onDelete: Cascade)\n\n  progress LessonProgress[]\n\n  @@map(\"lessons\")\n}\n\nenum LessonType {\n  TEXT\n  VIDEO\n  QUIZ\n}\n\n// Categoría\nmodel Category {\n  id      String                @id @default(cuid())\n  name    String                @unique\n  slug    String                @unique\n  courses CategoriesOnCourses[]\n\n  @@map(\"categories\")\n}\n\n// Relación muchos a muchos: Cursos <-> Categorías\nmodel CategoriesOnCourses {\n  courseId   String\n  categoryId String\n  course     Course   @relation(fields: [courseId], references: [id], onDelete: Cascade)\n  category   Category @relation(fields: [categoryId], references: [id], onDelete: Cascade)\n\n  @@id([courseId, categoryId])\n  @@map(\"categories_on_courses\")\n}\n\n// Inscripción a un curso\nmodel Enrollment {\n  id        String           @id @default(cuid())\n  status    EnrollmentStatus @default(ACTIVE)\n  createdAt DateTime         @default(now())\n  updatedAt DateTime         @updatedAt\n\n  userId   String\n  user     User   @relation(fields: [userId], references: [id], onDelete: Cascade)\n  courseId String\n  course   Course @relation(fields: [courseId], references: [id], onDelete: Cascade)\n\n  progress LessonProgress[]\n\n  @@unique([userId, courseId])\n  @@map(\"enrollments\")\n}\n\nenum EnrollmentStatus {\n  ACTIVE\n  COMPLETED\n  CANCELLED\n}\n\n// Progreso de lección\nmodel LessonProgress {\n  id          String    @id @default(cuid())\n  isCompleted Boolean   @default(false)\n  completedAt DateTime?\n  createdAt   DateTime  @default(now())\n  updatedAt   DateTime  @updatedAt\n\n  enrollmentId String\n  enrollment   Enrollment @relation(fields: [enrollmentId], references: [id], onDelete: Cascade)\n  lessonId     String\n  lesson       Lesson     @relation(fields: [lessonId], references: [id], onDelete: Cascade)\n\n  @@unique([enrollmentId, lessonId])\n  @@map(\"lesson_progress\")\n}\n",
